// ── CAPTAIN (image sprite, editable via M key) ──
window.createCaptain = function(bridgeRoomGroup, extraEditables) {
  const BRIDGE_ROOM_R = window.BRIDGE_ROOM_R || 280;

  var _textures = [null, null, null, null, null];
  var _captainMesh = null;
  var _mouthInterval = null;
  var _loadedCount = 0;
  // Wave cycle: 0→1→2→3→4→3→2→1→repeat
  var _cycle = [0, 1, 2, 3, 4, 3, 2, 1];
  var _cycleIdx = 0;

  function _onLoad(idx, tex) {
    tex.needsUpdate = true;
    _textures[idx] = tex;
    _loadedCount++;
    if (_loadedCount === 5) _build();
  }

  var _img1 = new Image();
  _img1.onload = function() { _onLoad(0, new THREE.Texture(_img1)); };
  _img1.src = 'data:image/png;base64,';

  var _img2 = new Image();
  _img2.onload = function() { _onLoad(1, new THREE.Texture(_img2)); };
  _img2.src = 'data:image/png;base64,';

  var _img3 = new Image();
  _img3.onload = function() { _onLoad(2, new THREE.Texture(_img3)); };
  _img3.src = 'data:image/png;base64,';

  var _img4 = new Image();
  _img4.onload = function() { _onLoad(3, new THREE.Texture(_img4)); };
  _img4.src = 'data:image/png;base64,';

  var _img5 = new Image();
  _img5.onload = function() { _onLoad(4, new THREE.Texture(_img5)); };
  _img5.src = 'data:image/png;base64,';

  function _build() {
    const spriteH = 94;
    const spriteW = spriteH * (438 / 680);
    _captainMesh = new THREE.Mesh(
      new THREE.PlaneGeometry(spriteW, spriteH),
      new THREE.MeshBasicMaterial({ map: _textures[0], transparent: true, alphaTest: 0.1 })
    );
    _captainMesh.name = 'captain';
    _captainMesh.position.set(90, spriteH / 2, BRIDGE_ROOM_R - 50);
    _captainMesh.rotation.y = 0;
    bridgeRoomGroup.add(_captainMesh);
    extraEditables.push(_captainMesh);
  }

  window.captainMouthStart = function() {
    if (!_captainMesh) return;
    _cycleIdx = 0;
    _mouthInterval = setInterval(function() {
      if (!_captainMesh) return;
      _cycleIdx = (_cycleIdx + 1) % _cycle.length;
      _captainMesh.material.map = _textures[_cycle[_cycleIdx]];
      _captainMesh.material.needsUpdate = true;
    }, 120);
  };

  window.captainMouthStop = function() {
    if (_mouthInterval) { clearInterval(_mouthInterval); _mouthInterval = null; }
    if (_captainMesh && _textures[0]) {
      _captainMesh.material.map = _textures[0];
      _captainMesh.material.needsUpdate = true;
    }
    _cycleIdx = 0;
  };
};
